prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created WHERE {
  ?org tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created .

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .
  ?task tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?taskName)), "invoice") && CONTAINS(LCASE(STR(?taskName)), "process"))
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created WHERE {
  ?org tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), "invoice") ||
    CONTAINS(LCASE(STR(?taskName)), "invoicing") ||
    CONTAINS(LCASE(STR(?taskName)), "billing") ||
    CONTAINS(LCASE(STR(?taskName)), "payment")
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?created ?taskName WHERE {
  ?org tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .
  FILTER(STRLEN(STR(?taskName)) > 0)
}
ORDER BY DESC(?created)
LIMIT 25
